import{_ as t,o as a,c as o,a0 as i}from"./chunks/framework.jwovEGr5.js";const c=JSON.parse('{"title":"Kingdom of Power","description":"","frontmatter":{},"headers":[],"relativePath":"events/kingdom-of-power.md","filePath":"events/kingdom-of-power.md"}'),r={name:"events/kingdom-of-power.md"};function s(l,e,n,h,p,d){return a(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="kingdom-of-power" tabindex="-1">Kingdom of Power <a class="header-anchor" href="#kingdom-of-power" aria-label="Permalink to &quot;Kingdom of Power&quot;">​</a></h1><p>Kingdom of Power is the default kingdom-wide multi-stage template for the main KvK preparation and competition cycle.</p><h2 id="how-this-default-is-set-up" tabindex="-1">How this default is set up <a class="header-anchor" href="#how-this-default-is-set-up" aria-label="Permalink to &quot;How this default is set up&quot;">​</a></h2><ul><li>event style: multi-stage</li><li>score entry: one score per row</li><li>default stage count: 5</li><li>default duration: 6 days</li><li>participation tracked: yes</li></ul><p>This default is usually used at <strong>kingdom</strong> scope rather than alliance scope.</p><h2 id="what-is-special-about-this-event" tabindex="-1">What is special about this event <a class="header-anchor" href="#what-is-special-about-this-event" aria-label="Permalink to &quot;What is special about this event&quot;">​</a></h2><p>Unlike most alliance events, Kingdom of Power often needs:</p><ul><li>kingdom-wide standings</li><li>phase-by-phase tracking</li><li>separate before/after power capture through KvK Prep</li></ul><p>The normal event results and the KvK Prep tool work together, but they are not the same page.</p><h2 id="what-to-import" tabindex="-1">What to import <a class="header-anchor" href="#what-to-import" aria-label="Permalink to &quot;What to import&quot;">​</a></h2><p>Use <strong>Kingdom event results</strong> when you are importing kingdom-wide screenshots for this event.</p><p>You can use:</p><ul><li><strong>Stage Data</strong> for a specific phase</li><li><strong>Total Data</strong> for overall standings</li></ul><p>For this default, the app does not force stage selection in the same strict way as Alliance Brawl, but you should still choose the correct mode yourself.</p><h2 id="kvk-prep-is-separate" tabindex="-1">KvK Prep is separate <a class="header-anchor" href="#kvk-prep-is-separate" aria-label="Permalink to &quot;KvK Prep is separate&quot;">​</a></h2><p>Before/after power snapshots belong in the dedicated KvK Prep workflow, not in normal result rows. See <a href="./../how-to/kvk-prep.html">Run a KvK Prep Session</a>.</p><h2 id="good-practice" tabindex="-1">Good practice <a class="header-anchor" href="#good-practice" aria-label="Permalink to &quot;Good practice&quot;">​</a></h2><ul><li>create one instance for the full KvK event window</li><li>keep normal event-result imports separate from before/after power snapshots</li><li>use kingdom-result scope when the screenshot is kingdom-wide</li></ul><h2 id="protection-note" tabindex="-1">Protection note <a class="header-anchor" href="#protection-note" aria-label="Permalink to &quot;Protection note&quot;">​</a></h2><p>This is a default template, so it is <strong>editable but not deletable</strong>. See <a href="./../roles/protection-rules.html">Safety Rules You&#39;ll Run Into</a>.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./default-events.html">The Default Events</a></li><li><a href="./../how-to/kvk-prep.html">Run a KvK Prep Session</a></li><li><a href="./../imports/upload-screenshots.html">Upload Screenshots</a></li></ul>',22)])])}const f=t(r,[["render",s]]);export{c as __pageData,f as default};
